{
  "task_scope": {
    "task_id": "DEV-008",
    "type": "batch_analysis",
    "audit_object": "超期报销（overdue reimbursement）及年末补充提交核对",
    "question": "扫描开发库中的超期报销，返回全部异常记录，并对年末补充提交记录进行核对。"
  },
  "audit_period": {
    "fiscal_year": "2025",
    "effective_policy": "XX证券费用报销管理办法(2025修订版)"
  },
  "policy_rules": [
    {
      "rule_id": "R1",
      "doc_id": "01_expense_reimbursement_2025.md",
      "clause": "第七条",
      "description": "员工应在费用发生后60天内提交报销申请；超过期限的，原则上不得报销。"
    },
    {
      "rule_id": "R2",
      "doc_id": "01_expense_reimbursement_2025.md",
      "clause": "第九条",
      "description": "会计年度末发生的费用，最迟可在财政年度结束后15天内补充提交，逾期按超期报销处理。"
    }
  ],
  "required_fields": ["record_id", "employee_id", "department_id", "expense_type", "expense_date", "reimburse_date", "amount", "status", "invoice_no", "special_approval"],
  "data_questions": [
    "列出所有报销记录，计算报销延迟天数（reimburse_date - expense_date）",
    "识别延迟超过60天的记录",
    "判断年末补充提交：费用日期属于会计年度末（需确认年末范围定义），且报销日期在次年1月15日之前",
    "排除年末补充提交有效豁免的记录后，剩余即为超期报销异常"
  ],
  "execution_steps": [
    {
      "step": "planning",
      "description": "制定审计计划，冻结规则和范围",
      "output": "work/audit_plan.json"
    },
    {
      "step": "policy_research",
      "description": "确认政策版本和适用条款，特别是第九条年末补充提交的精确范围定义",
      "output": "政策条款确认"
    },
    {
      "step": "subagent_batch_analysis",
      "description": "授权并调用data_analyst原生子智能体，批量获取全部报销记录并执行超期分析",
      "output": "work/subagents/data_analyst/ 下的详细分析和摘要"
    },
    {
      "step": "year_end_review",
      "description": "主上下文核对年末补充提交记录，确认豁免范围",
      "output": "年末豁免确认"
    },
    {
      "step": "evidence_coverage",
      "description": "运行evidence-coverage-check",
      "output": "work/evidence_matrix.json"
    },
    {
      "step": "false_positive_review",
      "description": "对年末边界记录进行独立复核",
      "output": "复核结果"
    },
    {
      "step": "reporting",
      "description": "生成审计报告",
      "output": "work/final_result.json"
    },
    {
      "step": "validation",
      "description": "运行result-validator校验",
      "output": "work/validation_report.json"
    },
    {
      "step": "submission",
      "description": "调用validate_audit_result和submit_audit_result提交",
      "output": "提交结果"
    }
  ],
  "complexity": {
    "score": 3,
    "reasons": [
      "涉及聚合、分组、批次过滤（+1）",
      "涉及两个业务规则：60天超期和年末补充提交（+1）",
      "涉及日期边界、阈值和豁免判断（+1）"
    ]
  },
  "subagent_plan": {
    "role": "data_analyst",
    "reason_code": "MULTI_RECORD_SCOPE",
    "task": "批量获取全部报销记录，计算每条记录的延迟天数（reimburse_date - expense_date），识别延迟超过60天的记录，并额外识别费用日期可能在年末（12月）且报销日期在次年1月的记录。返回所有延迟超过60天的记录列表及每个记录的详细信息。",
    "expected_artifacts": ["超期记录列表", "年末相关记录列表", "完整延迟分析摘要"]
  },
  "stopping_conditions": [
    "所有报销记录已扫描完毕",
    "延迟天数计算完成",
    "年末补充提交豁免已确认",
    "证据覆盖率达到100%",
    "校验通过"
  ],
  "unresolved_items": [
    "年末（会计年度末）的精确起始日期需要从政策上下文确认"
  ]
}

